const payload = items[0].json.body ?? items[0].json;
const leads = Array.isArray(payload) ? payload : (payload.leads ?? [payload]);

function cleanString(value) {
  return typeof value === 'string' ? value.trim() : '';
}

function pickLeadUrl(item) {
  const explicitLinkedin = cleanString(item['LinkedIn URL'] || item.linkedin_url);
  const fallbackUrl = cleanString(item.URL || item.website || '');
  if (explicitLinkedin) return explicitLinkedin;
  return fallbackUrl.includes('linkedin.com/company/') ? fallbackUrl : '';
}

return leads.map((item, index) => {
  const linkedinUrl = pickLeadUrl(item);
  const website = cleanString(item.Website || item.website || '');
  const salesScript = cleanString(item['Sales Script'] || item.sales_script || item.message || item.gonderilecek_mesaj || '');

  return {
    json: {
      source_index: index,
      sirket: cleanString(item.company_name || item.sirket || item.Sirket || ''),
      skor: Number(item.score || item.Skor || 0),
      website,
      linkedin_url: linkedinUrl,
      lead_url: linkedinUrl || website,
      mesaj: salesScript,
      kaynak: cleanString(item.kaynak || item.Kaynak || ''),
      detayli_analiz: cleanString(item.analysis || item.detayli_analiz || ''),
      lead_type: linkedinUrl ? 'linkedin_ready' : 'web_only'
    }
  };
});
